spec:
// Expo / EAS build configuration
// Files: app.json, app.config.js, eas.json

// app.json contains checked-in cross-platform metadata:
// - scheme: worktracker
// - ios.bundleIdentifier: com.worktracker.app
// - android.package: com.worktracker.app
// - android.intentFilters cover worktracker://auth/callback and https://worktracker.app/auth/callback
// - web.bundler: metro

// app.config.js injects env-driven values into expo.extra at config resolution time:
interface ExpoExtra {
  SUPABASE_URL: string;
  SUPABASE_ANON_KEY: string;
  eas: { projectId: string };
}

// Optional env inputs consumed by app.config.js:
// - SUPABASE_URL
// - SUPABASE_ANON_KEY
// - GOOGLE_IOS_REVERSED_CLIENT_ID
// - EAS_PROJECT_ID

// eas.json profiles:
// - development: development client, internal distribution, environment=development
// - preview: internal distribution, environment=preview
// - production: autoIncrement enabled, environment=production
// Each profile sets APP_ENV and expects secrets to live in the matching EAS environment.
